PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE Collections (
    id INTEGER PRIMARY KEY AUTOINCREMENT, 
    name TEXT NOT NULL,
    description TEXT,
    season TEXT,
    series TEXT, 
    edition TEXT,
    release_year INTEGER,
    themes TEXT,
    colours TEXT
, "name_friendly" TEXT, "type" TEXT, "image_urls" TEXT, releaseDate TEXT, exclusive TEXT);
CREATE TABLE Shapes (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL UNIQUE,
    measurements TEXT, -- Standard measurements for this shape
    category TEXT      -- e.g., 'Tote', 'Wallet'
, "name_friendly" TEXT, "size" TEXT, "description" TEXT);
CREATE TABLE Designs (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    collection_id INTEGER NOT NULL,
    shape_id INTEGER,
    name TEXT NOT NULL,
    description TEXT,
    image_urls TEXT,
    price REAL,
    release_year INTEGER,
    categories TEXT, -- Optional extra tags for a design
    FOREIGN KEY (collection_id) REFERENCES Collections(id) ON DELETE CASCADE,
    FOREIGN KEY (shape_id) REFERENCES Shapes(id) ON DELETE SET NULL
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_designs_collection_id ON Designs(collection_id);
CREATE INDEX idx_designs_shape_id ON Designs(shape_id);
CREATE UNIQUE INDEX idx_designs_name_unique
ON Designs(name);
CREATE UNIQUE INDEX idx_collection_name_unique
ON Collections(name COLLATE NOCASE);
CREATE UNIQUE INDEX idx_shapes_name_unique
ON Shapes(name COLLATE NOCASE);
